### Approach
1. **Binary Search Setup**: The binary search is performed over the possible time values `t`, ranging from 0 to the maximum time of any edge in the graph.
2. **Component Counting**: For each candidate `t` during the binary search, we construct the graph by including only edges with `time > t`. We then count the number of connected components in this graph using BFS.
3. **Binary Search Execution**: If the number of connected components for a given `t` is at least `k`, we adjust the search to find a potentially smaller `t` (since we want the minimal `t`). Otherwise, we look for a larger `t`.

### Solution Code
```kotlin
import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    var maxTime = 0L
    if (edges.isNotEmpty()) {
        maxTime = edges.maxOf { it[2] }
    }

    var low = 0L
    var high = maxTime

    while (low < high) {
        val mid = (low + high) / 2
        val comps = countComponents(n.toInt(), edges, mid)
        if (comps >= k) {
            high = mid
        } else {
            low = mid + 1
        }
    }
    return low
}

private fun countComponents(n: Int, edges: Array<Array<Long>>, t: Long): Long {
    val graph = Array(n) { mutableListOf<Int>() }
    for (edge in edges) {
        val time = edge[2]
        if (time > t) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            graph[u].add(v)
            graph[v].add(u)
        }
    }

    val visited = BooleanArray(n) { false }
    var count = 0
    val queue = LinkedList<Int>()
    for (i in 0 until n) {
        if (!visited[i]) {
            count++
            queue.add(i)
            visited[i] = true
            while (queue.isNotEmpty()) {
                val node = queue.poll()
                for (neighbor in graph[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true
                        queue.add(neighbor)
                    }
                }
            }
        }
    }
    return count.toLong()
}
```

